// Enhanced fetch wrapper
const originalFetch = global.fetch;

global.fetch = function(...args) {
  const startTime = Date.now();
  const url = args[0];
  const options = args[1];
  
  const requestBody = options?.body;
  const method = options?.method || 'GET';
  
  return originalFetch(...args)
    .then(response => {
      const duration = Date.now() - startTime;
      response.clone().text().then(text => {
        DebugLogger.logNetworkRequest(url, method, requestBody, {
          status: response.status,
          statusText: response.statusText,
          headers: Object.fromEntries(response.headers.entries()),
          body: text
        }, duration);
      });
      return response;
    })
    .catch(error => {
      const duration = Date.now() - startTime;
      DebugLogger.logNetworkRequest(url, method, requestBody, {
        error: error.message,
        status: 'error',
        duration
      }, duration);
      throw error;
    });
};

// Enhanced AsyncStorage wrapper
const originalAsyncStorage = AsyncStorage;

AsyncStorage.getItem = function(key) {
  return originalAsyncStorage.getItem(key)
    .then(result => {
      DebugLogger.logAsyncStorageOperation('get', key, null, result);
      return result;
    })
    .catch(error => {
      DebugLogger.logAsyncStorageOperation('get', key, null, { error: error.message });
      throw error;
    });
};

AsyncStorage.setItem = function(key, value) {
  return originalAsyncStorage.setItem(key, value)
    .then(result => {
      DebugLogger.logAsyncStorageOperation('set', key, value, result);
      return result;
    })
    .catch(error => {
      DebugLogger.logAsyncStorageOperation('set', key, value, { error: error.message });
      throw error;
    });
};

